import { getNetIQAccessToken } from '../lib';
import { expireToken } from '../lib/utils/cache-utils';

const dotenv = require('dotenv');

let username: string;
let password: string;
let client_id: string;
let client_secret: string;

beforeAll(() => {
  dotenv.config();
});

beforeAll(() => {
  username = process.env.NETIQ_ACCESS_TOKEN_IPN as string;
  password = process.env.NETIQ_ACCESS_TOKEN_PASSWORD as string;
  client_id = process.env.NETIQ_ACCESS_TOKEN_CLIENT_ID as string;
  client_secret = process.env.NETIQ_ACCESS_TOKEN_CLIENT_SECRET as string;
});

test('Get NETIQ access token from idp2', async () => {
  let token = await getNetIQAccessToken({
    username,
    password,
    client_id,
    client_secret,
  });
  expect(token.token_type).toBe('bearer');
});

test('Get NETIQ access token from cache', async () => {
  let token = await getNetIQAccessToken({
    username,
    password,
    client_id,
    client_secret,
    use_cache: false,
  });
  let previous = token.access_token;
  token = await getNetIQAccessToken({
    username,
    password,
    client_id,
    client_secret,
  });
  expect(token.token_type).toBe('bearer');
  expect(token.access_token).toBe(previous);
});

test('Refresh expired NETIQ access token', async () => {
  let token = await getNetIQAccessToken({
    username,
    password,
    client_id,
    client_secret,
    use_cache: false,
  });
  let previous = token.access_token;
  const key = `password:${username}@${client_id}:arca`;
  expireToken(key);
  token = await getNetIQAccessToken({
    username,
    password,
    client_id,
    client_secret,
  });
  expect(token.token_type).toBe('bearer');
  expect(token.access_token).not.toBe(previous);
});

test('Incorrect credentials for NETIQ access token', async () => {
  try {
    await getNetIQAccessToken({
      username: 'incorrect',
      password: 'incorrect',
      client_id,
      client_secret,
    });
    expect(true).toBe(false);
  } catch (error) {
    expect((error as Error).message).toBe(
      'Request failed with status code 400',
    );
  }
});
